const getMatchMedia = () => {
  if (typeof window !== 'undefined') {
    if (window.matchMedia('(max-width: 767.98px)').matches) {
      return 'sm'
    } else if (window.matchMedia('(max-width: 991.98px)').matches) {
      return 'md'
    } else {
      return 'lg'
    }
  }
}

export default getMatchMedia
